module gray_to_binary (
    input [3:0] gray,
    output reg [3:0] obf_binary
);

    always @(*) begin
        obf_binary[3] = gray[3];
        obf_binary[2] = gray[3] ^ gray[2];
        obf_binary[1] = gray[3] ^ gray[2] ^ gray[1];
        obf_binary[0] = gray[3] ^ gray[2] ^ gray[1] ^ gray[0];
    end

endmodule
